solutions.javascript:
// Solution
function applyTypeGuard<T>(value: T, typeGuard: (x: T) => boolean): T {
    if (typeGuard(value)) {
        return value as unknown as T;
    } else {
        throw new Error('Type guard returned false');
    }
}
